Definition shefferToHuntingtonFinal : list E :=
  match Certificate.runItems shefferInitial shefferToHuntingtonItems with
  | Some eqs => eqs
  | None => []
end.

Theorem shefferToHuntingtonRun :
    Certificate.runItems shefferInitial shefferToHuntingtonItems = Some shefferToHuntingtonFinal.
Proof. vm_compute. reflexivity. Qed.

Theorem shefferToHuntingtonKnown1 :
    Certificate.known shefferToHuntingtonFinal huntingtonEquation1 = true.
Proof. vm_compute. reflexivity. Qed.

Theorem shefferToHuntingtonKnown2 :
    Certificate.known shefferToHuntingtonFinal huntingtonEquation2 = true.
Proof. vm_compute. reflexivity. Qed.

Theorem shefferToHuntingtonKnown3 :
    Certificate.known shefferToHuntingtonFinal huntingtonEquation3 = true.
Proof. vm_compute. reflexivity. Qed.

Theorem shefferToHuntington_valid {A : Type} (op : A -> A -> A)
    (hS1 : Equation.Valid op LeanProofsCoq.WolframBooleanCertificates.LeanProofs.WolframBooleanCertificates.shefferEquation1)
    (hS2 : Equation.Valid op LeanProofsCoq.WolframBooleanCertificates.LeanProofs.WolframBooleanCertificates.shefferEquation2)
    (hS3 : Equation.Valid op LeanProofsCoq.WolframBooleanCertificates.LeanProofs.WolframBooleanCertificates.shefferEquation3) :
    Equation.Valid op huntingtonEquation1 /\
      Equation.Valid op huntingtonEquation2 /\ Equation.Valid op huntingtonEquation3.
Proof.
  pose proof (Certificate.runItems_sound (op := op) shefferToHuntingtonRun) as hsound.
  assert (hinitial : AllValid op shefferInitial).
  { intros eq he. simpl in he. destruct he as [<- | [<- | [<- | []]]].
    - exact hS1.
    - exact hS2.
    - exact hS3. }
  pose proof (hsound hinitial) as hall.
  split.
  - exact (Certificate.known_sound shefferToHuntingtonKnown1 hall).
  - split.
    + exact (Certificate.known_sound shefferToHuntingtonKnown2 hall).
    + exact (Certificate.known_sound shefferToHuntingtonKnown3 hall).
Qed.

